function solve(nums) {
    /**
     * Helper function to check if array T is a cyclic rotation of array B.
     * Assumes |T| == |B| = k.
     */
    const isCyclicRotation = (B, T) => {
        const k = B.length;
        if (k === 0) return true;

        // Create delimited string representations to prevent number merging (e.g., [1, 23] vs [12, 3])
        const B_str = B.join(',');
        const T_str = T.join(',');

        // T is a cyclic rotation of B if T appears as a substring in B concatenated with itself (B+B)
        // We append a delimiter to ensure the rotation spans across the boundary correctly.
        const extended_B_str = B_str + ',' + B_str;

        return extended_B_str.includes(T_str);
    };

    const n = nums.length;

    // 1. Sort nums to get S (the target sorted array)
    const S = [...nums].sort((a, b) => a - b);

    // 2. Find all divisors k of n
    const divisors = [];
    for (let k = 1; k * k <= n; k++) {
        if (n % k === 0) {
            divisors.push(k);
            if (k * k !== n) {
                divisors.push(n / k);
            }
        }
    }

    let sum_k = 0;

    // 3. Loop through divisors k
    for (const k of divisors) {
        let is_sortable = true;

        // 4. Iterate over blocks
        const m = n / k;
        for (let i = 0; i < m; i++) {
            const start = i * k;
            const end = (i + 1) * k;

            // i. Define B_i (original block)
            const B_i = nums.slice(start, end);

            // ii. Define S_i (target block)
            const S_i = S.slice(start, end);

            // iii. Check if S_i is a cyclic rotation of B_i
            if (!isCyclicRotation(B_i, S_i)) {
                is_sortable = false;
                break;
            }
        }

        // 5. Accumulate result
        if (is_sortable) {
            sum_k += k;
        }
    }

    return sum_k;
}

