object Solution {
    /**
     * Helper function to check if array T is a cyclic rotation of array B.
     * Time complexity: O(k), where k is the length of the arrays, assuming efficient string searching.
     */
    private def isCyclicRotation(B: Array[Long], T: Array[Long]): Boolean = {
        val k = B.length
        if (k == 0) return true
        if (k != T.length) return false

        // Using a delimiter to ensure numerical elements are treated as distinct units when converting to string.
        val delimiter = ","

        // Convert to delimited strings
        val B_str = B.map(_.toString).mkString(delimiter)
        val T_str = T.map(_.toString).mkString(delimiter)

        // T is a cyclic rotation of B if T appears as a substring in B concatenated with itself (with a delimiter separation).
        val extended_B_str = B_str + delimiter + B_str

        extended_B_str.contains(T_str)
    }

    def solve(nums: Array[Long]): Long = {
        val n = nums.length
        if (n == 0) return 0L

        // 1. Sort nums to get S (the target sorted array)
        val S = nums.sorted.toArray

        // 2. Find all divisors k of n
        var divisors = new scala.collection.mutable.Set[Int]()
        var d = 1
        while (d * d <= n) {
            if (n % d == 0) {
                divisors += d
                divisors += (n / d)
            }
            d += 1
        }

        var sumK: Long = 0

        // Convert set of divisors to iterable array/list
        val divisorList = divisors.toSeq.sortBy(_).map(_.toInt)

        // 3. Loop through divisors k
        for (k_int <- divisorList) {
            val k = k_int
            var isSortable = true

            // 4. Iterate over blocks
            val m = n / k // Number of blocks

            for (i <- 0 until m) {
                val start = i * k
                val end = (i + 1) * k

                // i. Define B_i (original block)
